import{_ as t,o,c as a,a4 as r}from"./chunks/framework.DyALjzgy.js";const g=JSON.parse('{"title":"Portal","description":"","frontmatter":{},"headers":[],"relativePath":"overview/components/portal.md","filePath":"overview/components/portal.md"}'),n={name:"overview/components/portal.md"};function i(s,e,c,l,d,h){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="portal" tabindex="-1">Portal <a class="header-anchor" href="#portal" aria-label="Permalink to &quot;Portal&quot;">​</a></h1><p>The <strong>Portal</strong> is the primary web interface for Platform Mesh. It is an Angular microfrontend shell built on the <a href="https://luigi-project.io" target="_blank" rel="noreferrer">Luigi</a> framework that composes IAM, Marketplace, and any custom extensions into a single, cohesive user experience.</p><hr><h2 id="purpose-and-responsibility" tabindex="-1">Purpose and Responsibility <a class="header-anchor" href="#purpose-and-responsibility" aria-label="Permalink to &quot;Purpose and Responsibility&quot;">​</a></h2><p>The Portal acts as the <strong>orchestration layer</strong> for the entire Platform Mesh UI surface. Its responsibilities are:</p><ul><li><strong>Workspace navigation</strong> — lets users traverse the KCP workspace hierarchy (root → org → account → namespace) with context-aware navigation nodes that update as the selected workspace changes</li><li><strong>Org / account / namespace management</strong> — surfaces CRUD operations for the main Platform Mesh entities, delegating rendering to embedded microfrontends</li><li><strong>Kubeconfig download</strong> — generates and serves a ready-to-use kubeconfig scoped to the current workspace</li><li><strong>Home dashboard</strong> — shows a summary of the current workspace context (owner, path, service bindings)</li><li><strong>Terminal-as-a-Service</strong> — an in-browser shell powered by xterm.js and a ttyd-based WebSocket backend, available when the <code>terminal</code> feature toggle is enabled</li><li><strong>Microfrontend orchestration</strong> — loads and frames IAM UI, Marketplace UI, and any registered extension microfrontends inside Luigi iframes with shared authentication context</li><li><strong>Authentication shell</strong> — handles the OIDC / OAuth2 login flow via the Luigi OAuth2 plugin and forwards JWT tokens to all child microfrontends</li></ul><hr><h2 id="key-concepts" tabindex="-1">Key Concepts <a class="header-anchor" href="#key-concepts" aria-label="Permalink to &quot;Key Concepts&quot;">​</a></h2><h3 id="luigi-micro-frontend-orchestration" tabindex="-1">Luigi Micro-Frontend Orchestration <a class="header-anchor" href="#luigi-micro-frontend-orchestration" aria-label="Permalink to &quot;Luigi Micro-Frontend Orchestration&quot;">​</a></h3><p>All routing inside the Portal is owned by <strong>Luigi</strong>, not the Angular router. The Angular router is intentionally empty; Luigi handles deep links, iframe lifecycle, and context propagation to child microfrontends. Navigation nodes (accounts, namespaces, IAM, Marketplace, Terminal) are built dynamically in TypeScript service classes that implement Luigi&#39;s node configuration interfaces.</p><h3 id="kcp-workspace-context" tabindex="-1">KCP Workspace Context <a class="header-anchor" href="#kcp-workspace-context" aria-label="Permalink to &quot;KCP Workspace Context&quot;">​</a></h3><p>Every navigation node is scoped to a <strong>KCP workspace path</strong> (e.g. <code>root:orgs:my-org:my-account</code>). The backend derives the active workspace path from the authenticated user&#39;s context and injects it into the Luigi <code>globalContext</code>, making it available to all child microfrontends without additional round-trips.</p>',12)])])}const u=t(n,[["render",i]]);export{g as __pageData,u as default};
